-- Replaces the inactive [DUMMY MOCK] debate row for fig-c-19 (The Bunnag
-- Family) with real content and flips is_active on. The row already existed
-- live (inserted directly, not through patch_debates.sql, which only seeds
-- king-taksin and si-suriyothai) — this file brings the tracked seed back
-- in sync with what's actually in the DB.
UPDATE history_debates
SET
  title_th = 'ตระกูลบุนนาค — ขุนนางผู้ค้ำจุนแผ่นดิน หรืออำนาจเหนือราชบัลลังก์?',
  case_a_title = 'เสาหลักผู้ค้ำจุนแผ่นดิน',
  case_a_text = 'ตระกูลบุนนาคดำรงตำแหน่งสมุหกลาโหมและสมุหนายกต่อเนื่องหลายรัชกาล ตั้งแต่รัชกาลที่ 2 ถึงรัชกาลที่ 5 มีบทบาทสำคัญทั้งด้านการทหาร การเจรจาต่างประเทศกับมหาอำนาจตะวันตก และการปฏิรูปการค้า ช่วยประคองสยามให้รอดพ้นจากยุคล่าอาณานิคมได้โดยไม่เสียเอกราชอย่างสมบูรณ์ นักประวัติศาสตร์บางส่วนมองว่าความเชี่ยวชาญและเครือข่ายของตระกูลนี้เป็นกลไกสำคัญที่ทำให้ราชสำนักรัตนโกสินทร์มีเสถียรภาพในช่วงเปลี่ยนผ่านที่อันตรายที่สุดช่วงหนึ่งของประวัติศาสตร์ไทย',
  case_b_title = 'อำนาจที่ถ่วงดุลราชบัลลังก์มากเกินไป',
  case_b_text = 'การผูกขาดตำแหน่งสมุหกลาโหมและสมุหนายกของตระกูลบุนนาคยาวนานหลายชั่วอายุคน ประกอบกับบทบาทเป็นผู้สำเร็จราชการในรัชกาลที่ 5 ตอนต้น ทำให้ตระกูลนี้มีอำนาจต่อรองกับพระราชอำนาจในระดับที่ไม่มีตระกูลขุนนางอื่นเทียบได้ นักวิชาการบางสำนักชี้ว่านี่คือภาวะที่ขุนนางตระกูลเดียวสะสมอำนาจจนเกือบเทียบเท่าผู้ปกครองถาวร ซึ่งเป็นส่วนหนึ่งของแรงกดดันที่นำไปสู่การปฏิรูปรวมศูนย์อำนาจในรัชกาลที่ 5',
  source_citations = 'Wyatt, D. (2003). Thailand: A Short History; Terwiel, B.J. (2011). Thailand''s Political History; ประวัติศาสตร์ราชวงศ์จักรี, กรมศิลปากร',
  is_active = true
WHERE figure_id = 'fig-c-19';
